143	  xs.reduce((m, x) => m.set(x[key]!, (m.get(x[key]!) ?? 0) + 1), new Map<string, number>());
144	
145	const validateDamageCounts = (policy: Policy, damages: Damage[]): void => {
146	  const insuredCounts = countByType(policy.items, "type");
147	  const damageCounts = countByType(damages, "itemType");
148	  damageCounts.forEach((count, type) => {
149	    if (count > (insuredCounts.get(type) ?? 0))
150	      throw new Error(`damage references more ${type} items than insured`);
151	  });
152	};
153	
154	const settleClaim = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
155	  validateDamageCounts(policy, incident.damages);
156	  const payout = Math.min(totalRawPayout(incident.damages, policy.items), policy.cap);
157	  policy.cap -= payout;
158	  return { payout, remainingCap: policy.cap };
