161	type QuoteResult = { premium: number };
162	type ClaimResult = { payout: number; remainingCap: number };
163	type StepResult = QuoteResult | ClaimResult;
164	
165	const processStep = (customer: Customer, policies: Policy[]) =>
166	  (step: Step, stepIndex: number): StepResult => {
167	    if (step.op === "quote") {
168	      policies[stepIndex] = openPolicy(step.items);
169	      return quoteResult(customer, step.items, stepIndex > 0);
170	    }
171	    return settleClaim(policies[step.policy], step.incident);
172	  };
173	
174	export const runScenario = (input: unknown): { results: StepResult[] } => {
175	  const { customer, steps } = input as Scenario;
176	  const policies: Policy[] = [];
177	  return { results: steps.map(processStep(customer, policies)) };
